    'nba', 'nfl', 'mlb', 'nhl', 'fifa', 'uefa', 'wimbledon', 'nascar', 'f1', 'rugby', 'cricket', 
    'athens', 'superbowl', 'worldcup', 'touchdown', 'homerun', 'grandslam'
}

